class Solution:
    def minAnagramLength(self, s: str) -> int:
        from math import gcd
        from functools import reduce

        n = len(s)
        freq = [0] * 26

        # Count frequency of each character in s
        for ch in s:
            freq[ord(ch) - ord('a')] += 1

        # Find the greatest common divisor (GCD) of all frequencies
        def compute_gcd(a, b):
            return gcd(a, b)

        total_gcd = reduce(compute_gcd, freq, 0)

        # The minimum length of t is n // total_gcd
        return n // total_gcd
